SELECT COUNT(*) AS TOTAL_SOFTWARE FROM LATTES_REG LR JOIN LATTES_P_REG LPR ON LPR.FK_REG = LR.PK JOIN SERVIDOR S ON S.PK_SIAPE = LPR.FK_SIAPE WHERE LOWER(LR.TIPO) = LOWER('software') AND LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%valparaiso%') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%engenharia civil%') AND LR.ANO = 2022